import { validateApiKey, jsonError, jsonSuccess } from "@/lib/api-auth";
import { db } from "@/db";
import { posts } from "@/db/schema";
import { eq, and } from "drizzle-orm";
import type { NextRequest } from "next/server";

export async function PATCH(
  request: NextRequest,
  { params }: { params: Promise<{ id: string }> }
) {
  const user = await validateApiKey(request);
  if (!user) return jsonError("Invalid or missing API key", 401);

  const { id } = await params;

  const [post] = await db
    .select()
    .from(posts)
    .where(and(eq(posts.id, id), eq(posts.userId, user.userId)));

  if (!post) return jsonError("Post not found", 404);
  if (post.status !== "queued" && post.status !== "draft")
    return jsonError(`Cannot approve a post with status '${post.status}'`);

  const [updated] = await db
    .update(posts)
    .set({ status: "approved", updatedAt: new Date() })
    .where(eq(posts.id, id))
    .returning();

  return jsonSuccess(updated);
}

